(function(){
  "use strict";
  const OA=window.OrbArena,esc=(value)=>String(value??"").replace(/[&<>"']/g,(char)=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[char]));
  class BestiaryUI{
    constructor(app){this.app=app;this.ensure();}
    ensure(){document.querySelector(".screen-stack").insertAdjacentHTML("beforeend",`<section class="screen module-screen" id="screen-bestiary"><div class="module-page"><header class="module-head"><button class="back-button" data-go-home>← MENU</button><div><span class="eyebrow">10 · ARQUIVO DE ENTIDADES · IV</span><h1>BESTIÁRIO</h1><p>Descubra inimigos, registre encontros e transforme observação em vantagem.</p></div></header><div class="discovery-legend"><span>Desconhecido</span><span>Avistado</span><span>Enfrentado</span><span>Derrotado</span><span>Dominado</span></div><div class="module-toolbar"><input data-search type="search" placeholder="Buscar criatura…"><select data-state><option value="">Todos os estados</option><option>Desconhecido</option><option>Enfrentado</option><option>Derrotado</option><option>Dominado</option></select><select data-class><option value="">Todas as classes</option></select><select data-rarity><option value="">Todas as raridades</option></select><label><input data-defeated type="checkbox"> Apenas derrotados</label></div><div class="module-split"><div class="catalog-grid" data-list></div><aside class="panel module-detail" data-detail><div class="empty-state">Esta criatura ainda não foi selecionada.</div></aside></div></div></section>`);const screen=document.querySelector("#screen-bestiary");screen.querySelector("[data-go-home]").onclick=()=>this.app.goHome();screen.querySelectorAll("input,select").forEach((element)=>element.oninput=()=>this.render());for(const [selector,values] of [["[data-class]",[...new Set(OA.CharacterRegistry.all().map((item)=>item.class))]],["[data-rarity]",[...new Set(OA.CharacterRegistry.all().map((item)=>item.rarity))]]])screen.querySelector(selector).insertAdjacentHTML("beforeend",values.sort().map((value)=>`<option>${esc(value)}</option>`).join(""));}
    open(selected=null){this.render();this.app.showScreen("bestiary");if(selected)this.detail(selected);}
    render(){const screen=document.querySelector("#screen-bestiary"),search=screen.querySelector("[data-search]").value.toLowerCase(),state=screen.querySelector("[data-state]").value,cls=screen.querySelector("[data-class]").value,rarity=screen.querySelector("[data-rarity]").value,defeated=screen.querySelector("[data-defeated]").checked;let entries=this.app.progression.all().filter((entry)=>`${entry.character.name} ${entry.character.title} ${entry.character.tags.join(" ")}`.toLowerCase().includes(search)&&(!state||entry.state===state)&&(!cls||entry.character.class===cls)&&(!rarity||entry.character.rarity===rarity)&&(!defeated||entry.wins>0));screen.querySelector("[data-list]").innerHTML=entries.map((entry,index)=>{const hidden=entry.state==="Desconhecido";return`<article class="panel catalog-card bestiary-card ${hidden?"undiscovered":""}" data-id="${entry.characterId}"><div class="bestiary-orb" style="--orb:${hidden?"#26313b":entry.character.color}">${hidden?"?":esc(entry.character.icon)}</div><small>#${String(index+1).padStart(3,"0")} · ${entry.state}</small><h2>${hidden?"ENTIDADE DESCONHECIDA":esc(entry.character.name)}</h2><p>${hidden?"Enfrente esta entidade para revelar seus dados.":`${esc(entry.character.class)} · ${esc(entry.character.rarity)}`}</p></article>`;}).join("");screen.querySelectorAll("[data-id]").forEach((card)=>card.onclick=()=>this.detail(card.dataset.id));}
    detail(id){const entry=this.app.progression.all().find((item)=>item.characterId===id);if(!entry)return;const c=entry.character,level=["Desconhecido","Avistado","Enfrentado","Derrotado","Dominado"].indexOf(entry.state),host=document.querySelector("#screen-bestiary [data-detail]");this.app.state.selectedBestiaryEntry=entry;host.innerHTML=`<small>#${esc(c.id)} · ${entry.state}</small><h2>${level<1?"ENTIDADE DESCONHECIDA":esc(c.name)}</h2><p>${level<1?"Dados bloqueados até o primeiro encontro.":esc(c.description)}</p><dl><dt>Tipo</dt><dd>${c.tags.includes("invocação")?"Invocação":"Combatente"}</dd><dt>Classe</dt><dd>${level>=1?esc(c.class):"—"}</dd><dt>Raridade</dt><dd>${level>=1?esc(c.rarity):"—"}</dd><dt>Poderes</dt><dd>${level>=2?esc([c.kit.active,c.kit.reactive,c.kit.ultimate].join(", ")):"—"}</dd><dt>Fraquezas</dt><dd>${level>=3?esc(c.weaknesses.join(", ")):"Derrote para revelar"}</dd><dt>Resistências</dt><dd>${level>=4?esc(c.strengths.join(", ")):"Domine para revelar"}</dd><dt>Encontros</dt><dd>${entry.encounters}</dd><dt>Vitórias / derrotas</dt><dd>${entry.wins} / ${entry.losses}</dd><dt>Taxa de vitória</dt><dd>${entry.winRate}%</dd><dt>Último encontro</dt><dd>${entry.lastEncounter?new Date(entry.lastEncounter).toLocaleString("pt-BR"):"Nunca"}</dd></dl><div class="detail-actions"><button data-action="battle">Criar batalha contra</button><button data-action="matchup">Testar matchup</button><button data-action="history">Ver histórico</button><button data-action="builds">Ver builds usadas</button><button data-action="favorite">Favoritar</button><button data-action="copy">Copiar informações</button><button data-action="character">Abrir personagem</button></div>`;host.querySelectorAll("[data-action]").forEach((button)=>button.onclick=()=>this.action(button.dataset.action,entry));}
    async action(action,entry){const c=entry.character;if(action==="battle"||action==="matchup"){const build=this.app.state.currentBuild||this.app.buildSystem.create();this.app.startBattle({...build,color:OA.CharacterRegistry.get(build.characterId).color,stroke:"#fff",trailColor:"#55dce8"},"normal",OA.Random.createSeed(),OA.getPhysicsPreset(build.physicsPreset),{arenaId:"classic",enemyCharacterId:c.id,mode:action==="matchup"?"lab":"duel"});}else if(action==="history"){this.app.archiveUI.openHistory();const field=document.querySelector("#screen-history [data-search]");field.value=c.name;this.app.archiveUI.renderHistory();}else if(action==="builds")this.app.archiveUI.openBuilds(entry.bestBuildId);else if(action==="favorite"){this.app.storage.updateBestiary(c.id,{favorite:!entry.favorite});this.render();}else if(action==="copy"){await navigator.clipboard.writeText(`${c.name} — ${c.description}`);this.app.toast("Informações copiadas.");}else if(action==="character"){this.app.openCharacterSelect();setTimeout(()=>this.app.characterSelectUI.select?.(c.id),0);}}
  }
  OA.BestiaryUI=BestiaryUI;
}());
